import 'package:http/http.dart' as http;
import 'dart:convert';

class ApiService {
  final String cloudApiUrl = "https://api.example.com";
  final String localIotDeviceUrl = "http://192.168.x.x";

  Future<Map<String, dynamic>> fetchData(String url) async {
    try {
      final response = await http.get(Uri.parse(url));

      if (response.statusCode == 200) {
        return json.decode(response.body);
      } else {
        throw Exception('Failed to load data: ${response.statusCode}');
      }
    } catch (e) {
      throw Exception('Error during communication with the server: $e');
    }
  }

  Future<void> sendData(String url, Map<String, dynamic> data) async {
    try {
      final response = await http.post(
        Uri.parse(url),
        headers: {'Content-Type': 'application/json'},
        body: json.encode(data),
      );

      if (response.statusCode != 200) {
        throw Exception('Failed to send data: ${response.statusCode}');
      }
    } catch (e) {
      throw Exception('Error during communication with the server: $e');
    }
  }

  Future<void> updateData(String url, Map<String, dynamic> data) async {
    try {
      final response = await http.put(
        Uri.parse(url),
        headers: {'Content-Type': 'application/json'},
        body: json.encode(data),
      );

      if (response.statusCode != 200) {
        throw Exception('Failed to update data: ${response.statusCode}');
      }
    } catch (e) {
